/// Validates and restricts which hosts are allowed for cleartext HTTP.
/// Only local IoT devices on the private subnet are permitted.
class CleartextPolicy {
  /// Checks whether the given URI is allowed.
  /// - HTTPS is always allowed (cloud API, secure IoT devices).
  /// - HTTP is ONLY allowed for known local IoT device addresses.
  static bool isAllowed(Uri uri) {
    if (uri.scheme == 'https') {
      return true;
    }

    if (uri.scheme == 'http') {
      return _isAllowedIotAddress(uri);
    }

    return false;
  }

  /// Determines if an HTTP URI targets a valid local IoT device.
  static bool _isAllowedIotAddress(Uri uri) {
    final host = uri.host;

    // Only allow private 192.168.x.x addresses
    if (!host.startsWith(ApiConfig.iotSubnet)) {
      return false;
    }

    // Validate it's a proper IPv4 in the 192.168.x.x range
    final parts = host.split('.');
    if (parts.length != 4) return false;

    for (final part in parts) {
      final num = int.tryParse(part);
      if (num == null || num < 0 || num > 255) return false;
    }

    // Restrict allowed ports
    final port = uri.hasPort ? uri.port : 80;
    if (!ApiConfig.allowedIotPorts.contains(port)) {
      return false;
    }

    return true;
  }

  /// Classifies the target type based on the URI.
  static TargetType classifyTarget(Uri uri) {
    if (_isAllowedIotAddress(uri) && uri.scheme == 'http') {
      return TargetType.iotDevice;
    }
    return TargetType.cloudApi;
  }
}

