/// Retry wrapper for transient failures.
class RetryHttpService {
  final HttpService _httpService;
  final int maxRetries;
  final Duration retryDelay;
  final void Function(String)? _logger;

  RetryHttpService({
    required HttpService httpService,
    this.maxRetries = 3,
    this.retryDelay = const Duration(seconds: 1),
    void Function(String)? logger,
  })  : _httpService = httpService,
        _logger = logger;

  /// Executes a request with retry logic for transient failures.
  Future<ApiResponse<Map<String, dynamic>>> withRetry(
    Future<ApiResponse<Map<String, dynamic>>> Function() request,
  ) async {
    ApiException? lastException;

    for (int attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        if (attempt > 0) {
          final delay = retryDelay * attempt; // Linear backoff
          _logger?.call('Retry attempt $attempt after ${delay.inMilliseconds}ms');
          await Future.delayed(delay);
        }

        return await request();
      } on ApiException catch (e) {
        lastException = e;

        // Only retry on server errors or timeouts, not client errors
        final isRetryable = e.statusCode == null || // timeout/connection error
            (e.statusCode != null && e.statusCode! >= 500);

        if (!isRetryable || attempt == maxRetries) {
          rethrow;
        }

        _logger?.call('Retryable error: ${e.message}');
      }
    }

    throw lastException ??
        ApiException(message: 'Request failed after $maxRetries retries');
  }

  void dispose() {
    _httpService.dispose();
  }
}

