Future<void> exampleUsage() async {
  final httpService = HttpService(
    authToken: 'your-secure-token-here',
    logger: print,
  );

  final retryService = RetryHttpService(
    httpService: httpService,
    maxRetries: 3,
    logger: print,
  );

  try {
    // Cloud API call — always HTTPS, with auth token
    final users = await retryService.withRetry(
      () => httpService.cloudGet('/api/v1/users'),
    );
    print('Cloud users: ${users.data}');

    // IoT device call — HTTP allowed only on 192.168.x.x
    final sensorData = await httpService.iotGet(
      '192.168.1.100',
      '/api/sensors/temperature',
      port: 80,
    );
    print('Sensor data: ${sensorData.data}');

    // Send command to IoT device
    final commandResult = await httpService.iotPost(
      '192.168.1.100',
      '/api/control/led',
      port: 80,
      body: {'state': 'on', 'brightness': 75},
    );
    print('Command result: ${commandResult.data}');

    // This would THROW — cleartext HTTP to a non-local address is blocked:
    // final bad = await httpService.iotGet('10.0.0.1', '/api/data');

    // Discover devices on the local network
    final devices = await httpService.discoverIotDevices(
      subnet: '192.168.1',
      port: 80,
    );
    print('Discovered devices: $devices');
  } on ApiException catch (e) {
    print('API Error: $e');
  } finally {
    retryService.dispose();
  }
}